@namespace sv_cc3a2b5e772947fb86ec6a1cff478b5b.Components.Pages.Board

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="text-muted small">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft" disabled="@IsMoving">← Move Left</button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight" disabled="@IsMoving">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private bool IsMoving;

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task HandleMove(EventCallback callback)
    {
        IsMoving = true;
        try { await callback.InvokeAsync(); }
        finally { IsMoving = false; }
    }
}

@namespace sv_cc3a2b5e772947fb86ec6a1cff478b5b.Components.Pages.Board

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card mt-2">
        <div class="card-body p-2">
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
            </div>
            <div class="mb-2">
                <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="Priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="DueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@IsSaving">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@IsSaving">Cancel</button>
            </div>
            @if (!string.IsNullOrEmpty(Error))
            {
                <div class="text-danger small mt-1">@Error</div>
            }
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private bool IsSaving;
    private string Title = "";
    private string Assignee = "";
    private string Priority = "Medium";
    private DateTime DueDate = DateTime.Today.AddDays(7);
    private string? Error;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(Title))
        {
            Error = "Title is required.";
            return;
        }

        IsSaving = true;
        Error = null;
        try
        {
            await OnTaskCreated.InvokeAsync(
                new TaskItem(0, Title.Trim(), Assignee.Trim(), Priority, DueDate, Status));
            ResetForm();
            IsVisible = false;
        }
        catch (Exception ex)
        {
            Error = ex.Message;
        }
        finally
        {
            IsSaving = false;
        }
    }

    private void ResetForm()
    {
        Title = "";
        Assignee = "";
        Priority = "Medium";
        DueDate = DateTime.Today.AddDays(7);
        Error = null;
    }
}

@namespace sv_cc3a2b5e772947fb86ec6a1cff478b5b.Components.Pages.Board

<div class="d-flex flex-wrap gap-3 mb-3 p-2 bg-light rounded">
    <span class="badge bg-primary fs-6">Total: @Tasks.Count</span>
    <span class="badge bg-secondary fs-6">To Do: @TodoCount</span>
    <span class="badge bg-info text-dark fs-6">In Progress: @InProgressCount</span>
    <span class="badge bg-success fs-6">Done: @DoneCount</span>
    <span class="badge bg-danger fs-6">Overdue: @OverdueCount</span>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();

    private int TodoCount => Tasks.Count(t => t.Status == "To Do");
    private int InProgressCount => Tasks.Count(t => t.Status == "In Progress");
    private int DoneCount => Tasks.Count(t => t.Status == "Done");
    private int OverdueCount => Tasks.Count(t => t.DueDate < DateTime.Today);
}

@namespace sv_cc3a2b5e772947fb86ec6a1cff478b5b.Components.Pages.Board

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await OnSearchChanged.InvokeAsync(value);
    }
}

@namespace sv_cc3a2b5e772947fb86ec6a1cff478b5b.Components.Pages.Board

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, -1))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, 1))" />
            }
            <AddTaskForm Status="@ColumnName" OnTaskCreated="OnAddTask" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, int Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<TaskItem> OnAddTask { get; set; }
}

@page "/board"
@namespace sv_cc3a2b5e772947fb86ec6a1cff478b5b.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @for (var i = 0; i < columns.Length; i++)
        {
            var columnIndex = i;
            var columnName = columns[columnIndex];
            <KanbanColumn ColumnName="@columnName"
                          Tasks="GetFilteredTasksForColumn(columnName)"
                          ShowMoveLeft="columnIndex > 0"
                          ShowMoveRight="columnIndex < columns.Length - 1"
                          OnMoveTask="args => MoveTask(args.TaskId, columnIndex, args.Direction)"
                          OnAddTask="CreateTask" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasksForColumn(string status)
    {
        var query = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            query = query.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchTerm = value;
    }

    private async Task MoveTask(int taskId, int currentColumnIndex, int direction)
    {
        var newIndex = currentColumnIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task CreateTask(TaskItem formData)
    {
        var created = await TaskService.CreateTaskAsync(
            formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
        allTasks.Add(created);
    }
}

