{"file_text": "@page "/board"
@namespace sv_cc3a2b5e772947fb86ec6a1cff478b5b.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />
    <BoardSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @for (var i = 0; i < columns.Length; i++)
        {
            var columnIndex = i;
            var columnName = columns[columnIndex];
            <KanbanColumn ColumnName="@columnName"
                          Tasks="GetFilteredTasksForColumn(columnName)"
                          ShowMoveLeft="columnIndex > 0"
                          ShowMoveRight="columnIndex < columns.Length - 1"
                          OnMoveTask="args => MoveTask(args.TaskId, columnIndex, args.Direction)"
                          OnAddTask="CreateTask" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasksForColumn(string status)
    {
        var query = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            query = query.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    private void HandleSearchChanged(string value)
    {
        searchTerm = value;
    }

    private async Task MoveTask(int taskId, int currentColumnIndex, int direction)
    {
        var newIndex = currentColumnIndex + direction;
        if (newIndex < 0 || newIndex >= columns.Length) return;

        var newStatus = columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == taskId);
            if (task is not null)
            {
                allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task CreateTask(TaskItem formData)
    {
        var created = await TaskService.CreateTaskAsync(
            formData.Title, formData.Assignee, formData.Priority, formData.DueDate);
        allTasks.Add(created);
    }
}
